class DirectoryEntry:
    def __init__(self, filename, metadata):
        self.filename = filename
        self.metadata = metadata
        self.next = None

class HashDirectory:
    def __init__(self, size=100):
        self.size = size
        self.table = [None] * size

    def _hash(self, filename):
        return hash(filename) % self.size

    def insert(self, filename, metadata):
        index = self._hash(filename)
        entry = DirectoryEntry(filename, metadata)
        entry.next = self.table[index]
        self.table[index] = entry

    def search(self, filename):
        index = self._hash(filename)
        current = self.table[index]
        while current:
            if current.filename == filename:
                return current.metadata
            current = current.next
        return None

# Time Complexity: O(1) average, O(n) worst case
# Space Complexity: O(n) for n entries

#define NUM_DIRECT_BLOCKS 12
#define POINTER_SIZE 4

struct inode {
    int inode_number;
    int file_type;        // Regular file, directory, etc.
    int link_count;
    uid_t owner_uid;
    gid_t owner_gid;
    off_t file_size;
    time_t access_time;
    time_t modify_time;
    time_t change_time;

    // Block pointers
    int direct_blocks[NUM_DIRECT_BLOCKS];   // 12 direct pointers
    int single_indirect;    // Level 1 indirect blocks
    int double_indirect;    // Level 2 indirect blocks
    int triple_indirect;    // Level 3 indirect blocks
};

/* Maximum file size calculation:
 * Direct: 12 * 4KB = 48KB
 * Single indirect: 1024 * 4KB = 4MB
 * Double indirect: 1024 * 1024 * 4KB = 4GB
 * Triple indirect: 1024^3 * 4KB = 4TB */
